com.mirth.connect.plugins.javascriptstep.script:
var requestedPath = sourceMap.get('contextPath');
if (requestedPath == "/" || requestedPath == "/healthcheck") {
	return;
}

var mtlsEnabled = globalChannelMap.get('mtlsFilterEnabled');
if (String(mtlsEnabled) !== 'true') {
	logger.error('[RouterChannel] mTLS filter is disabled – rejecting request with 500');
	channelMap.put('mtlsFilterDisabled', 'true');
	destinationSet.removeAll();
	return;
}

var requestedPath = sourceMap.get('contextPath');
if (requestedPath == "/" ||  requestedPath ==  "/healthcheck") {
	return;
}
var incomingInterationId = $('headers').getHeader('X-TechBD-Interaction-ID');
var interactionId;
if (incomingInterationId != null && incomingInterationId.trim() !== '') {
    interactionId = incomingInterationId;
}
else {
    interactionId = generateUuid();
}
channelMap.put("interactionId", interactionId);
var logPrefix = "[INTERACTION ID: " + interactionId + "] ";

logger.info(logPrefix + "Request URL inside RouterChannel: " + requestedPath);

var contentType = $('headers').getHeader('Content-Type');
channelMap.put("contentType", contentType);

//Detect whether this request is targeting an HL7 upload endpoint so we can
// apply HL7-specific validation (zero-file guard) without affecting other route paths.
var normalizedContentType = String(contentType || "").toLowerCase();
var hasMultipartContentType = normalizedContentType.indexOf("multipart/form-data") === 0;
var isHl7UploadEndpoint =
    requestedPath == "/hl7v2/Bundle/" || requestedPath == "/hl7v2/Bundle" ||
    requestedPath == "/hl7v2/Bundle/$validate/" || requestedPath == "/hl7v2/Bundle/$validate";

// Zero-file guard at the router level for HL7 endpoints.
// When Postman sends with all file rows unchecked the Content-Type still carries a valid boundary
// so the downstream HL7 channel's boundary check passes, but filename=" is absent from the raw body.
// Catching it here at the router means we never forward to port 9006 at all; destinationSet.removeAll()
// stops the destination from firing, and the postprocessor's routerDirectResponse block then returns
// a proper 400 OperationOutcome to the caller.
if (isHl7UploadEndpoint && hasMultipartContentType) {
    var rawBody = connectorMessage.getRawData();
    var hasFilePart = rawBody.indexOf('filename="') !== -1;
     if (!hasFilePart) {
        logger.error(logPrefix +"[RouterChannel] HL7 zero-file guard triggered.");

        channelMap.put("routerDirectStatus", "400");
        channelMap.put("routerDirectResponse", JSON.stringify({
            status: 400,
            message: "Uploaded file is empty or missing."
        }));
        destinationSet.removeAll();
        return;
    }
}

interactionId = channelMap.get("interactionId");
var logPrefix = "[INTERACTION ID: " + interactionId + "] ";

if (requestedPath == "/Bundle/" || requestedPath == "/Bundle") {
	channelMap.put('destinationUrl', "http://localhost:9003" + requestedPath); 	
	logger.info(logPrefix + "FHIRBundle submission  RouterChannel ");
}

else if (requestedPath == "/Bundle/$validate/" || requestedPath == "/Bundle/$validate") {
	channelMap.put('destinationUrl', "http://localhost:9001" + requestedPath);
	logger.info(logPrefix + "FHIRBundle validation  RouterChannel ");
}


else if (requestedPath == "/ccda/Bundle/" || requestedPath == "/ccda/Bundle") {
	channelMap.put('destinationUrl', "http://localhost:9002" + requestedPath);	
	logger.info(logPrefix + "CCDA submission  RouterChannel ");
}

else if (requestedPath == "/ccda/Bundle/$validate/" || requestedPath == "/ccda/Bundle/$validate") {
	channelMap.put('destinationUrl', "http://localhost:9002" + requestedPath);	
	logger.info(logPrefix + "CCDA validation  RouterChannel ");
}


else if (requestedPath == "/flatfile/csv/Bundle/" || requestedPath == "/flatfile/csv/Bundle") {
	channelMap.put('destinationUrl', "http://localhost:9004" + requestedPath);
	logger.info(logPrefix + "CSV FlatFile submission  RouterChannel ");
}

else if (requestedPath == "/flatfile/csv/Bundle/$validate/" || requestedPath == "/flatfile/csv/Bundle/$validate") {
	channelMap.put('destinationUrl', "http://localhost:9004" + requestedPath);
	logger.info(logPrefix + "CSV FlatFile validation  RouterChannel ");
}

else if (requestedPath == "/hl7v2/Bundle/" || requestedPath == "/hl7v2/Bundle") {
	channelMap.put('destinationUrl', "http://localhost:9006" + requestedPath);	
	logger.info(logPrefix + "HL7 submission  RouterChannel ");
}



else if (requestedPath == "/hl7v2/Bundle/$validate/" || requestedPath == "/hl7v2/Bundle/$validate") {
	channelMap.put('destinationUrl', "http://localhost:9006" + requestedPath);	
	logger.info(logPrefix + "HL7 validation  RouterChannel ");
}
else if (requestedPath == "/Bundle/replay/" || requestedPath == "/Bundle/replay") {
	channelMap.put('destinationUrl', "http://localhost:9005" + requestedPath);	
	logger.info(logPrefix + "Replay validation  RouterChannel ");
}
else{
	return;
}


var fhirJson  = connectorMessage.getRawData();
channelMap.put('fhirJson', fhirJson);
logger.info(fhirJson);

com.mirth.connect.plugins.javascriptrule.script:
var httpMethod = String(sourceMap.get('method')).toUpperCase();
var contextPath = String(connectorMessage.getSourceMap().get('contextPath')).replace(/\/$/, '');


var hostHeader = $('headers').getHeader('Host');

if (hostHeader != null) {

    var hostname =
        String(hostHeader)
            .split(':')[0]
            .toLowerCase()
            .trim();

    // Read allowed hosts from Lookup Manager
    var allowedHostConfig =
        String(
            LookupHelper.get("Config", "ALLOWED_HOSTS") || ''
        ).toLowerCase();

    // Convert comma separated string to array
    var allowedHosts =
        allowedHostConfig
            .split(',');

    // Trim spaces
    for (var i = 0; i < allowedHosts.length; i++) {
        allowedHosts[i] =
            allowedHosts[i].trim();
    }

    // Validate host
    if (allowedHosts.indexOf(hostname) === -1) {

        logger.error(
            'Invalid Host header: ' + hostname
        );

        var errorBody = JSON.stringify({
            status: 400,
            error: 'Invalid Host header'
        });

        var errorResponse =
            new com.mirth.connect.userutil.Response(
                com.mirth.connect.userutil.Status.ERROR,
                new java.lang.String(errorBody)
            );

        responseMap.put('d1', errorResponse);

        responseMap.put('status', '400');
        responseMap.put('responseStatusCode', 400);
        responseMap.put('responseContentType', 'application/json');
        responseMap.put('responseBody', errorBody);

        return false;
    }
}

// HEALTHCHECK
if (contextPath === '/healthcheck') {

	if (httpMethod === 'GET') {
		responseMap.put('responseStatusCode', 200);
		responseMap.put('responseContentType', 'application/json');
		responseMap.put('responseBody', JSON.stringify({
			status: 200,
			message: "OK"
		}));
	
		return false;
	}

	return methodNotAllowed();
}


// Helper Functions

function methodNotAllowed() {

	var errorResponse = "Method Not Allowed.";

	responseMap.put('responseStatusCode', 405);
	responseMap.put('responseContentType', 'application/json');
	responseMap.put('responseBody', JSON.stringify(errorResponse));

	setErrorResponse(405, errorResponse);

	throw "Invalid method";
}




// Signal that the mTLS filter rule is active (checked by source transformer)
globalChannelMap.put('mtlsFilterEnabled', true);

var remoteAddress = sourceMap.get('remoteAddress') || '';

var group1 = $('headers').getHeader('X-TechBD-Group-Interaction-ID');

var group2 = $('headers').getHeader('X-TechBD-Interaction-ID');
channelMap.put('group2', group2);
logger.info("Interaction-ID inside RouterChannel filter: " + group2 + 'contextPath' + contextPath );

var sourceType = $('headers').getHeader('X-TechBD-Source-Type');

if(sourceType == "CSV") { // TODO: Add a dedicated condition to handle the health check when the filter is enabled.
	return true;
} else {
	return performCertValidation("chain", "Util-sbx-bl-net.JKS", null);
}

com.mirth.connect.plugins.javascriptstep.script:
var requestedPath = sourceMap.get('contextPath');
if (requestedPath == "/" ||  requestedPath ==  "/healthcheck") {
  return;
}
interactionId = channelMap.get("interactionId");
var logPrefix = "[INTERACTION ID: " + interactionId + "] ";

// ======================================================
// PARSE HEADERS STRING + FORWARD
// ======================================================
var headersMap = new java.util.HashMap();
var headers = $('headers');
logger.info(logPrefix + "HEADERS OBJECT: " + $('headers'));
if (headers != null) {
    var headerStr = String(headers);  // Convert full object to string
    // Remove { and }
    headerStr = headerStr.replace(/^\{|\}$/g, '');
    var pairs = headerStr.split(', ');
    for (var i = 0; i < pairs.length; i++) {    var idx = pairs[i].indexOf('=');
    if (idx > 0) {

        var key = pairs[i].substring(0, idx).trim();
        var value = pairs[i].substring(idx + 1).trim();
            // Remove [ ]
            var headerValue = value.replace(/^\[|\]$/g, '');

            if (headerValue !== '' && key.toLowerCase() !== 'content-length') {
               // logger.info("INCOMING HEADER: " + key + " = " + headerValue);
                headersMap.put(key, headerValue);
            }
        }
    }
}

headersMap.put("X-TechBD-Interaction-ID", interactionId);
logger.info(logPrefix + "Added X-TechBD-Interaction-ID to router headers: " + interactionId);
// Send headers via HTTP Sender
connectorMap.put("routerheaders", headersMap);



var paramsMap = new java.util.HashMap();
var inboundParams = $('parameters'); // Get query params from source

if (inboundParams != null) {
    var paramsStr = String(inboundParams);

    // Clean the { } brackets
    paramsStr = paramsStr.replace(/^\{|\}$/g, '');

    if (paramsStr.length > 0) {
        var pPairs = paramsStr.split(', ');
        for (var j = 0; j < pPairs.length; j++) {
            var pParts = pPairs[j].split('=');
            if (pParts.length === 2) {
                var pKey = pParts[0].trim();
                var pValue = pParts[1].trim();

                // Clean the [ ] brackets from the value
                var finalPValue = pValue.replace(/^\[|\]$/g, '');

                if (finalPValue !== '') {
                    paramsMap.put(pKey, finalPValue);
                }
            }
        }
    }
}

// Store for the HTTP Sender
connectorMap.put("routerparams", paramsMap);




// CRITICAL: REMOVE BODY COMPLETELY
return '';

channel.postprocessingScript:
var requestedPath = sourceMap.get('contextPath');
if (requestedPath == "/" || requestedPath == "/healthcheck") {
    return;
}
interactionId = channelMap.get("interactionId");
var logPrefix = "[INTERACTION ID: " + interactionId + "] ";

//Router-level direct error handler.
// If the zero-file guard set
// routerDirectResponse in channelMap, we build a proper Response object from it and
// return immediately with the correct status code, bypassing all downstream response logic.
var routerDirectResponse = channelMap.get('routerDirectResponse');
if (routerDirectResponse != null && String(routerDirectResponse).trim() !== '') {
    var routerDirectStatus = String(channelMap.get('routerDirectStatus') || '400');
    var routerResp = new com.mirth.connect.userutil.Response(
        com.mirth.connect.userutil.Status.SENT,
        new java.lang.String(String(routerDirectResponse))
    );
    responseMap.put('d1', routerResp);
    responseMap.put('status', routerDirectStatus);
    logger.error(logPrefix + '[RouterChannel] PostProcessor: returning router direct response, status=' + routerDirectStatus);
    return;
}

// =========================
// mTLS DISABLED CHECK
// =========================
if (String(channelMap.get('mtlsFilterDisabled')) === 'true') {

    var mtlsErrorBody = JSON.stringify({
        code: 500,
        message: "mTLS filter is disabled."
    });

    var mtlsResp = new com.mirth.connect.userutil.Response(
        com.mirth.connect.userutil.Status.ERROR,
        new java.lang.String(mtlsErrorBody)
    );

    responseMap.put('d1', mtlsResp);
    responseMap.put('status', '500');

    logger.error(logPrefix + 'PostProcessor: mTLS filter disabled - returning 500');
    return;
}

// =========================
// GET DESTINATION RESPONSE
// =========================
var destinationName = "response_operationoutcome";
var destinationResponse = responseMap.get(destinationName);

logger.info(logPrefix + 'DEBUG#1 | destinationResponse exists: ' + (destinationResponse != null));

// =========================
// NO RESPONSE → 502
// =========================
if (!destinationResponse) {

    logger.error(logPrefix + "PostProcessor: No response from destination");

    var noResponseOutcome = JSON.stringify({
        resourceType: "OperationOutcome",
        issue: [{
            severity: "error",
            code: "exception",
            diagnostics: "No response received from downstream service."
        }]
    });

    var newResp = new com.mirth.connect.userutil.Response(
        com.mirth.connect.userutil.Status.SENT,
        new java.lang.String(noResponseOutcome)
    );

    responseMap.put(destinationName, newResp);
    responseMap.put('status', '502');
    return;
}

// =========================
// READ RESPONSE
// =========================
var responseStatus = String(destinationResponse.getStatus());
var responseData = String(destinationResponse.getMessage() || '').trim();

logger.info(logPrefix + 'DEBUG#2 | responseStatus: ' + responseStatus);
logger.info(logPrefix + 'DEBUG#3 | responseData (first 500): ' + responseData.substring(0, 500));

// =========================
// ERROR HANDLING
// =========================
if (responseStatus === 'ERROR') {

    var responseError = '';
    try { responseError = String(destinationResponse.getError()); } catch (ex) {}

    var statusMessage = String(destinationResponse.getStatusMessage() || '');
    var rawErrorDetail = responseError + ' ' + statusMessage + ' ' + responseData;
    var errorText = rawErrorDetail.toLowerCase();

    logger.error('PostProcessor ERROR detail: ' + rawErrorDetail);

    // ---- TIMEOUT → 504 ----
    if (errorText.indexOf('timeout') !== -1 ||
        errorText.indexOf('timed out') !== -1 ||
        errorText.indexOf('sockettimeoutexception') !== -1 ||
        errorText.indexOf('read timed out') !== -1) {

        var timeoutOutcome = JSON.stringify({
            resourceType: "OperationOutcome",
            issue: [{
                severity: "error",
                code: "timeout",
                diagnostics: "The downstream service did not respond within the allowed time."
            }]
        });

        destinationResponse.setMessage(new java.lang.String(timeoutOutcome));
        destinationResponse.setStatus(com.mirth.connect.userutil.Status.SENT);

        responseMap.put('status', '504');
        return;
    }

    // ---- CONNECTION REFUSED → 502 ----
    if (errorText.indexOf('connection refused') !== -1 ||
        errorText.indexOf('connectexception') !== -1) {

        var connRefusedOutcome = JSON.stringify({
            resourceType: "OperationOutcome",
            issue: [{
                severity: "error",
                code: "exception",
                diagnostics: "Unable to connect to the downstream service."
            }]
        });

        destinationResponse.setMessage(new java.lang.String(connRefusedOutcome));
        destinationResponse.setStatus(com.mirth.connect.userutil.Status.SENT);

        responseMap.put('status', '502');
        return;
    }

    // ---- EXTRACT STATUS FROM BODY ----
    var extractedStatus = null;

    try {
        var parsed = JSON.parse(responseData);
        if (parsed && parsed.status != null) {
            extractedStatus = parseInt(parsed.status);
            logger.info('DEBUG#4 | Extracted status: ' + extractedStatus);
        }
    } catch (e) {
        // fallback regex
        var match = errorText.match(/"status"\s*:\s*(\d{3})/);
        if (match) {
            extractedStatus = parseInt(match[1]);
            logger.info('DEBUG#5 | Extracted via regex: ' + extractedStatus);
        }
    }

    var statusNum = Number(extractedStatus);

    // ---- PASS THROUGH ERROR (NO WRAP) ----
    if (!isNaN(statusNum) && statusNum >= 400) {

        destinationResponse.setMessage(new java.lang.String(responseData));
        destinationResponse.setStatus(com.mirth.connect.userutil.Status.SENT);

        responseMap.put('status', String(statusNum));
        return;
    }


    var fallbackOutcome = JSON.stringify({
        resourceType: "OperationOutcome",
        issue: [{
            severity: "error",
            code: "exception",
            diagnostics: "Unknown downstream error."
        }]
    });

    destinationResponse.setMessage(new java.lang.String(fallbackOutcome));
    destinationResponse.setStatus(com.mirth.connect.userutil.Status.SENT);

    responseMap.put('status', '502');
    return;
}

// =========================
// SUCCESS FLOW
// =========================

//Backstop safety net for HL7 endpoints.
// If the downstream HL7 channel somehow returned an empty body, we must not
// silently return 200. For HL7 upload endpoints an empty response always signals a failure
// return 400 with an OperationOutcome instead of the previous unconditional 200.
if (responseData === "") {
    var isHl7Path = (requestedPath == "/hl7v2/Bundle/" || requestedPath == "/hl7v2/Bundle" ||
                     requestedPath == "/hl7v2/Bundle/$validate/" || requestedPath == "/hl7v2/Bundle/$validate");
    if (isHl7Path) {
        var emptyOutcome = JSON.stringify({
            resourceType: "OperationOutcome",
            issue: [{ severity: "error", code: "invalid",
                      diagnostics: "Bad Request: No file is selected. Please attach a .hl7 or .txt file." }]
        });
        destinationResponse.setMessage(new java.lang.String(emptyOutcome));
        destinationResponse.setStatus(com.mirth.connect.userutil.Status.SENT);
        responseMap.put('status', '400');
        logger.error(logPrefix + '[RouterChannel] PostProcessor: HL7 empty-response backstop triggered, returning 400');
        return;
    }
    responseMap.put('status', '200');
    return;
}

// Try to extract status from JSON
try {
    var json = JSON.parse(responseData);

    if (json.status != null && json.status !== "") {
        responseMap.put('status', String(json.status));
    } else {
        responseMap.put('status', '200');
    }

} catch (e) {
    // Non-JSON → assume success
    responseMap.put('status', '200');
}

