/**
	Do Client certificate validation using certificate provided in http header coming from AWS Load Balancer

	@param {String} arg1 - arg1 description
	@return {String} return description
*/
function performCertValidation(validationType, truststoreName, allowedPattern){
	try {
		// workaround for healthcheck
		if(sourceMap.get("uri") == "/healthcheck"){ 
			return true;
		}

		// Get the certificate header from source connector
		var certHeader = cleanCertHeader(String(sourceMap.get('headers').getHeader('x-amzn-mtls-clientcert'))); 
          //logger.info(channelName + " - x-amzn-mtls-clientcert: " + sourceMap.getHeader('x-amzn-mtls-clientcert'));

		if (!certHeader) {
		    logger.error(channelName + " - No client certificate found in header");
		    // Reject the message or handle as needed
		    throw channelName + " - No client certificate found in header";
		    return;
		}

		// Load your truststore (you already have this code)
		
		var cfgController = Packages.com.mirth.connect.server.controllers.ControllerFactory.getFactory().createConfigurationController();
		var properties = cfgController.getPropertiesForGroup("SSL Settings", null);
		var certManagerProps = new Packages.com.innovarhealthcare.ssl.shared.model.CertificateManagerProperties(properties);

		var trustStoreName = truststoreName; // Configure this
		var trustStoreKeyStoreInfo = certManagerProps.getTrustedStoreMap().get(trustStoreName);
		var truststore = new Packages.java.security.KeyStore.getInstance(trustStoreKeyStoreInfo.getType());
		var truststoreStream = new java.io.ByteArrayInputStream(trustStoreKeyStoreInfo.getData());
		truststore.load(truststoreStream, trustStoreKeyStoreInfo.getPassword().toCharArray());

		//logger.info("Truststore loaded successfully");

		// Validate the certificate chain
		var validationResult = validateClientCertificate(certHeader, truststore, validationType, allowedPattern);
		//var validationResult = validateCertificateChain(certHeader, truststore);


		if (validationResult.success) {
			logger.info("Client certificate validated successfully");
			logger.info("Subject: " + validationResult.subject);
			logger.info("Serial: " + validationResult.serialNumber);

		    // Store validation results in channel map for downstream use
//		    channelMap.put('certValidated', true);
//		    channelMap.put('certSubject', validationResult.subject);
//		    channelMap.put('certIssuer', validationResult.issuer);

		    // Continue processing the message

		} else {
		    	logger.error("Client certificate validation failed: " + validationResult.error);

		    	// Store failure information
			channelMap.put('certValidated', false);
			channelMap.put('certError', validationResult.error);

		    // Reject the message or send error response
		    // Example: Return a SOAP fault or HTTP error
		    //responseMap.put('errorMessage', 'Certificate validation failed: ' + validationResult.error);

		    return false;
		}

		return true;

	}
	catch(exp){
		//logger.error(channelName + " - failed client cert validation - Exception: " + exp);
		return false;
		//throw exp; 
	}
}



function cleanCertHeader(urlEncodedCert) {
    // Manually decode %XX sequences but leave + alone
    var decoded = "";

    for (var i = 0; i < urlEncodedCert.length; i++) {
        if (urlEncodedCert.charAt(i) === '%' && i + 2 < urlEncodedCert.length) {
            var hex = urlEncodedCert.substring(i + 1, i + 3);
            decoded += String.fromCharCode(parseInt(hex, 16));
            i += 2;
        } else {
            decoded += urlEncodedCert.charAt(i);
        }
    }

    return decoded;
}

/**
 * Alternative simpler validation - just check if any cert in chain is in truststore
 * @param {Array} certChain - Array of X509Certificate objects
 * @param {KeyStore} truststore - The truststore
 * @returns {Object} Validation result
 */
function simpleValidation(certChain, truststore) {
    try {
        var aliases = truststore.aliases();

        // Check each certificate in the chain
        while (aliases.hasMoreElements()) {
            var alias = aliases.nextElement();
            var trustedCert = truststore.getCertificate(alias);

            if (trustedCert == null) {
                continue;
            }

            // Check if any certificate in the chain matches or is issued by a trusted cert
            for (var i = 0; i < certChain.length; i++) {
                var cert = certChain[i];

                // Direct match
                if (cert.equals(trustedCert)) {
                    logger.info("Certificate directly trusted: " + alias);
                    return {
                        success: true,
                        trustedAlias: alias,
                        matchedCert: cert.getSubjectX500Principal().getName()
                    };
                }

                // Check if issued by trusted cert
                try {
                    cert.verify(trustedCert.getPublicKey());
                    logger.info("Certificate verified by trusted issuer: " + alias);
                    return {
                        success: true,
                        trustedAlias: alias,
                        verifiedBy: trustedCert.getSubjectX500Principal().getName()
                    };
                } catch (verifyError) {
                    // Not issued by this trusted cert, continue checking
                }
            }
        }

        return {
            success: false,
            error: "No trusted certificate found in chain"
        };

    } catch (e) {
        logger.error("Simple validation error: " + e);
        return {
            success: false,
            error: "Validation error: " + e.message
        };
    }
}

/**
 * Deploy Script: Increase Jetty Request Header Size
 * 
 * Problem: AWS ALB with mTLS forwards the full client certificate chain in HTTP headers
 * (e.g. X-Amzn-Mtls-Clientcert-Chain). With 2+ intermediate certs, this can exceed
 * Jetty's default 8KB (8192 bytes) request header limit, resulting in HTTP 431
 * "Request Header Fields Too Large" errors.
 *
 * Solution: After the channel finishes deploying, this script stops the Jetty connector,
 * replaces the HttpConnectionFactory with one configured for a larger header size (32KB),
 * and restarts the connector. This runs in a background thread with a delay to ensure
 * the channel is fully deployed before modifying the connector.
 *
 * Note: There is a brief (~1 second) window during the connector stop/start where the
 * HTTP listener will not accept connections. This only occurs during channel deployment.
 *
 * TODO: This is a workaround. Ideally, requestHeaderSize should be a configurable 
 * property on the HTTP Listener connector or in DefaultHttpConfiguration.java.
 */
function updateRequestHeaderSize() {
	// Store channelId as a Java String so it survives beyond the deploy script context.
	// Rhino's closure doesn't reliably capture Mirth context variables into background threads.
	var myChannelId = new java.lang.String(channelId);

	var thread = new java.lang.Thread(function() {
	    try {
	        // Wait for the channel to fully deploy and the Jetty server/connectors to initialize.
	        // Increase this if the channel hasn't finished deploying in time.
	        java.lang.Thread.sleep(5000);

	        var HttpConnectionFactory = org.eclipse.jetty.server.HttpConnectionFactory;
	        var donkey = com.mirth.connect.donkey.server.Donkey.getInstance();
	        var deployedChannel = donkey.getDeployedChannels().get(myChannelId);
	        var sourceConnector = deployedChannel.getSourceConnector();

	        // The HttpReceiver exposes the embedded Jetty Server directly via getServer()
	        var server = sourceConnector.getServer();
	        var connectors = server.getConnectors();

	        for (var i = 0; i < connectors.length; i++) {
	            var connector = connectors[i];

	            // Must stop the connector before modifying factories (Jetty throws
	            // IllegalStateException: STARTED if you try to modify a running connector)
	            connector.stop();

	            var factories = connector.getConnectionFactories();
	            var iterator = factories.iterator();
	            while (iterator.hasNext()) {
	                var factory = iterator.next();
	                if (factory instanceof HttpConnectionFactory) {
	                    // Copy the existing config (preserves SSL settings, send server version, etc.)
	                    // and override just the request header size
	                    var oldConfig = factory.getHttpConfiguration();
	                    var newConfig = new org.eclipse.jetty.server.HttpConfiguration(oldConfig);
	                    newConfig.setRequestHeaderSize(32768); // 32KB — enough for full mTLS cert chain + other headers

	                    // Swap out the old factory for one using the new config
	                    var newFactory = new HttpConnectionFactory(newConfig);
	                    connector.removeConnectionFactory(factory.getProtocol());
	                    connector.addConnectionFactory(newFactory);

	                    logger.info("Replaced HttpConnectionFactory with requestHeaderSize: " + newConfig.getRequestHeaderSize());
	                }
	            }

	            // Restart the connector with the updated configuration
	            connector.start();
	            logger.info("Connector restarted on port: " + connector.getPort());
	        }
	    } catch (e) {
	        logger.error("Failed to update requestHeaderSize: " + e);
	    }
	});

	// Daemon thread so it won't prevent JVM shutdown
	thread.setDaemon(true);
	thread.setName("header-size-fix-" + myChannelId);
	thread.start();
}

/**
 * Validates the certificate chain against the truststore
 * @param {Array} certChain - Array of X509Certificate objects
 * @param {KeyStore} truststore - The truststore
 * @returns {Object} Validation result
 */
function validateCertificateChain(certChain, truststore) {
    try {
        // Create a CertPathValidator
        var certPathValidator = Packages.java.security.cert.CertPathValidator.getInstance("PKIX");

        // Create a CertPath from the certificate chain
        var certFactory = Packages.java.security.cert.CertificateFactory.getInstance("X.509");
        var certList = java.util.Arrays.asList(certChain);
        var certPath = certFactory.generateCertPath(certList);

        // Create PKIXParameters with the truststore
        var pkixParams = new Packages.java.security.cert.PKIXParameters(truststore);

        // Disable revocation checking (enable if you have OCSP/CRL configured)
        pkixParams.setRevocationEnabled(false);

        // Validate the certificate path
        var result = certPathValidator.validate(certPath, pkixParams);

        //logger.info("Certificate chain validated successfully");
        return {
            success: true,
            trustAnchor: result.getTrustAnchor().getTrustedCert().getSubjectX500Principal().getName()
        };

    } catch (e) {
        //logger.error(channelName + " - Certificate chain validation failed: " + e);
        return {
            success: false,
            error: "Certificate chain validation failed: " + e.message
        };
    }
}

/**
 * Validates certificate by checking if it's directly in the truststore (certificate pinning)
 * @param {Array} certChain - Array of X509Certificate objects
 * @param {KeyStore} truststore - The truststore containing leaf certificates
 * @returns {Object} Validation result
 */
function validateCertificateLeaf(certChain, truststore) {
    try {
        var clientCert = certChain[0]; // First cert is the client cert

        // Check if the client certificate is directly in the truststore
        var aliases = truststore.aliases();

        while (aliases.hasMoreElements()) {
            var alias = aliases.nextElement();
            var trustedCert = truststore.getCertificate(alias);

            if (trustedCert != null && clientCert.equals(trustedCert)) {
               // logger.info("Certificate matched trusted certificate: " + alias);
                return {
                    success: true,
                    trustedAlias: alias,
                    matchType: "direct"
                };
            }
        }

        // No match found
        return {
            success: false,
            error: "Client certificate not found in truststore"
        };

    } catch (e) {
        logger.error(channelName + " - Certificate validation failed: " + e);
        return {
            success: false,
            error: "Certificate validation failed: " + e.message
        };
    }
}

/**
 * Validates client certificate Subject DN and Subject Alternative Names (SANs) against allowed patterns.
 * Provides an additional security layer by ensuring certificates match expected organizational identifiers
 * even if they are signed by a trusted CA.
 * 
 * @param {java.security.cert.X509Certificate} clientCert - The client certificate to validate
 * @param {Object} allowedPatterns - Object containing allowed patterns for matching
 * @param {Array<String>} [allowedPatterns.subjects] - Array of string patterns to match against Subject DN (e.g., ["CN=*.example.com", "O=Example Org"])
 * @param {Array<String>} [allowedPatterns.sans] - Array of string patterns or regex to match against SANs (e.g., ["example.com", ".*\\.example\\.com"])
 * @returns {Object} Validation result object
 * @returns {boolean} returns.success - Whether validation succeeded
 * @returns {string} [returns.matched] - What was matched: "subject" or "san"
 * @returns {string} [returns.value] - The actual value that matched
 * @returns {string} [returns.error] - Error message if validation failed
 * 
 * @example
 * // Allow certificates with specific organizational unit
 * var patterns = {
 *     subjects: ["OU=Healthcare", "O=Hospital System"],
 *     sans: [".*\\.hospitalnet\\.org"]
 * };
 * var result = validateCertificateSubject(clientCert, patterns);
 * if (!result.success) {
 *     logger.error("Subject validation failed: " + result.error);
 * }
 */
function validateCertificateSubject(clientCert, allowedPatterns) {
    try {
        var subject = clientCert.getSubjectX500Principal().getName();

        // Check Subject DN
        for each (var pattern in allowedPatterns.subjects || []) {
            if (subject.contains(pattern)) {
                return { success: true, matched: "subject", value: subject };
            }
        }

        // Check SAN (Subject Alternative Names)
        var sanCollection = clientCert.getSubjectAlternativeNames();
        if (sanCollection != null) {
            var sanIterator = sanCollection.iterator();
            while (sanIterator.hasNext()) {
                var san = sanIterator.next();
                var sanType = san.get(0); // 2 = DNS, 1 = email, 6 = URI
                var sanValue = san.get(1).toString();

                for each (var pattern in allowedPatterns.sans || []) {
                    if (sanValue.contains(pattern) || sanValue.matches(pattern)) {
                        return { success: true, matched: "san", value: sanValue };
                    }
                }
            }
        }

        return {
            success: false,
            error: "Certificate subject/SAN does not match allowed patterns"
        };

    } catch (e) {
        return {
            success: false,
            error: "Subject validation failed: " + e.message
        };
    }
}

/**
 * Validates the client certificate from the header against the truststore
 * @param {string} certHeader - The URL-encoded certificate chain from the header
 * @param {KeyStore} truststore - The loaded truststore
 * @returns {Object} Validation result with success flag and details
 */
function validateClientCertificate(certHeader, truststore, validationType, allowedPatterns) {
    try {

        // Step 1: Parse the certificate chain
        var certFactory = Packages.java.security.cert.CertificateFactory.getInstance("X.509");
        var certStream = new java.io.ByteArrayInputStream(new java.lang.String(certHeader).getBytes("UTF-8"));
        var certChain = certFactory.generateCertificates(certStream);

        if (certChain.isEmpty()) {
            return {
                success: false,
                error: "No certificates found in header"
            };
        }

        //logger.info("Parsed " + certChain.size() + " certificates from chain");

        // Convert to array for easier handling
        var certArray = certChain.toArray();
        var clientCert = certArray[0]; // First certificate is the client certificate

        // Step 3: Validate certificate dates
        try {
            clientCert.checkValidity();
            //logger.info("Certificate is within valid date range");
        } catch (e) {
            return {
                success: false,
                error: "Certificate is expired or not yet valid: " + e.message,
                subject: clientCert.getSubjectX500Principal().getName()
            };
        }

	   // Step 3.5: Validate subject/SAN if patterns provided
	   if (allowedPatterns != undefined && allowedPatterns != null) {
	   	var subjectResult = validateCertificateSubject(clientCert, allowedPatterns);
		if (!subjectResult.success) {
		    return subjectResult;
		}
	   }

        // Step 4: Validate against truststore
        var validationResult = null;
        if(validationType == "chain"){
        	validationResult = validateCertificateChain(certArray, truststore);
        }
        else {
        	validationResult = validateCertificateLeaf(certArray, truststore);
        }
        if (validationResult.success) {
            return {
                success: true,
                subject: clientCert.getSubjectX500Principal().getName(),
                issuer: clientCert.getIssuerX500Principal().getName(),
                serialNumber: clientCert.getSerialNumber().toString(16),
                notBefore: clientCert.getNotBefore(),
                notAfter: clientCert.getNotAfter(),
                chainLength: certArray.length,
                message: "Certificate validated successfully"
            };
        } else {
            return validationResult;
        }

    } catch (e) {
        //logger.error(channelName + " - Certificate validation error: " + e);
        return {
            success: false,
            error: "Certificate validation failed: " + e.message
        };
    }
}

/**
	Util function to set error response.

	@param {Any} statusCode - 
	@param {Any} errorMessage - 
	@param {Any} map - 
	@return {Any} 
*/
function setErrorResponse(statusCode, errorMessage, map) {
    var targetMap = map || responseMap;

    var json = createJsonResponse(statusCode, errorMessage);
    targetMap.put('status', String(statusCode));
    targetMap.put('responseStatusCode', statusCode);
    targetMap.put('fhirResponse', json);
    targetMap.put('finalResponse', json);
}
/**
 Util function to generate json string wit hstatus and message
*/
function createJsonResponse(status, message) {
    return JSON.stringify({ status: status, message: message });
}

function getUuidGenerator() {
    var generator = globalMap.get('UUID_GENERATOR');

    if (generator == null) {
        var Generators = Packages.com.fasterxml.uuid.Generators;
        generator = Generators.timeBasedEpochGenerator();

        globalMap.put('UUID_GENERATOR', generator);
        logger.info('UUID Generator initialized ONCE');
    }

    return generator;
}

function generateUuid() {
    return getUuidGenerator().generate().toString();
}
